#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long T1, T2, T3, T4;
        scanf("%lld %lld %lld %lld", &T1, &T2, &T3, &T4);
        double ans = (double)T1 / (double)(T1 + T2);
        printf("%.10f\n", ans);
    }
    return 0;
}

