code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long T1 = Long.parseLong(st.nextToken());
            long T2 = Long.parseLong(st.nextToken());
            st.nextToken(); // T3, not needed
            st.nextToken(); // T4, not needed
            double ans = (double) T1 / (double) (T1 + T2);
            out.append(String.format(Locale.US, "%.10f", ans)).append('\n');
        }
        System.out.print(out.toString());
    }
}

